import React from "react";
import { useLocation, useNavigate } from "react-router-dom";

export default function RequestDetails() {
  const { state } = useLocation();
  const navigate = useNavigate();
  const order = state?.request;

  if (!order) {
    return <p>Request details not available.</p>;
  }

  const settings = order.perPageSettings || [];

  const intOrZero = val => {
    const x = parseInt(val);
    return isNaN(x) ? 0 : x;
  };

  return (
    <div className="p-6">
      <button onClick={() => navigate(-1)} className="mb-4 text-blue-500 underline">
        ← Back
      </button>

      <h2 className="text-2xl font-bold mb-4">Request Details</h2>
      <p><strong>ID:</strong> <code>{order.id}</code></p>
      <p><strong>Student:</strong> {order.studentName || "Unknown"}</p>
      <p><strong>Submitted:</strong> {order.timestamp ? new Date(order.timestamp.seconds * 1000).toLocaleString() : "Unknown"}</p>
      <p><strong>Status:</strong> {order.status}</p>

      <div className="mt-4">
        <strong>File:</strong>{" "}
        <a href={order.fileUrl} target="_blank" rel="noopener noreferrer" className="text-blue-500 underline">
          View / Download
        </a>
      </div>

      <section className="mt-6">
        <h3 className="text-lg font-semibold mb-2">🧾 Batch & Print Settings</h3>
        {settings.length > 0 && (
          <>
            <h4 className="font-semibold mb-1">Per-Page Settings:</h4>
            {settings.map((s, idx) => (
              <div key={idx} className="text-sm">
                Page {s.page} → {s.type} ({s.copies} copies)
              </div>
            ))}
          </>
        )}

        <div className="mt-3 space-y-1 text-sm">
          <div><strong>Pages:</strong> {order.pages ?? "N/A"}</div>
          <div><strong>Copies (batch):</strong> {order.copies ?? "N/A"}</div>
          <div><strong>Print Type:</strong> {order.printType ?? "N/A"}</div>
          <div><strong>Color Option:</strong> {order.color ?? "N/A"}</div>
          <div><strong>Binding:</strong> {order.binding ? "Yes" : "No"}</div>
          <div><strong>Punch:</strong> {order.punch ? "Yes" : "No"}</div>
          <div><strong>Staple:</strong> {order.staple ? "Yes" : "No"}</div>
          <div><strong>Total Price:</strong> ₹{intOrZero(order.price)}</div>
        </div>
      </section>
    </div>
  );
}
